sp_widget.client_script:
api.controller=function($scope) {
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below

	/* widget controller */
	var c = this;

	main();

	function main() {		
		_loadFormWidget();
	}

	function _loadFormWidget(){
		// STRY0130635 - only set if not set by server
		if(!c.data.sidebarMenuItem || c.data.sidebarMenuItem == ""){
			// set the selected sidebar menu item to the first one in the menu list
			c.data.sidebarMenuItem = c.data.sidebarMenuList[0];
		}
	}

	$scope.selectedMenu = function(selectedItem) {
		// switch to the User selected sidebar menu item
		c.data.sidebarMenuItem = selectedItem;
	};

	// 2.8.1 | 2023-01-03 | mmcc | STRY0130942 - Tasker User Profile as Modal; this story only needs to close the modal
	c.onSubmit = function() {
//         c.data.submit = true;
//         $scope.server.update().then(function() {
//             $scope.$parent.$parent.$dismiss();
//         });

		$scope.$parent.$parent.$dismiss();
    };

};

sp_widget.css:
.detech-flex-shadow-25 {
  box-shadow: 0px 0px 30px 0px rgba(0, 0, 0, 0.25);
} 

.component-selector {
  background: #F5F7F9;
}

/* mmcc 14-Nov-2022 seems not used; leaving in if needed in the future
.component-selector-divider {
width: 100%;
height: 2px;
background-color: rgba(221, 221, 221, 1);
}
*/

.component-selector-header{
  color: rgba(117, 117, 117, 1); /*508 AA*/
  width: 100%;
  padding: 14px 20px 14px 20px;
  font-size: 14px;
  font-weight: 400;
  text-transform: uppercase;
}


.ul-selector {
  margin: 0px;
  padding: 0px;
  list-style-type: none;
  color:#757575;
}

.li-flex-row {
  display: flex;
  flex-grow:0;
  width:100%;
  flex-direction:row;
}

.flex-text {
  flex-grow:1;
}

.li-flex-row-left-pointer {
  width: 0px;
  height: 0px;
  border-left: 10px solid transparent;
  border-right: 10px solid  white;
  border-top: 10px solid  transparent;
  border-bottom: 10px solid  transparent;
  margin: 0px auto;
  z-index: 1000;
}

.li-selector {
  padding: 14px 0px 14px 40px;
  width: 100%;
  color: rgba(0, 0, 0, 1);
  font-size: 14px;
  font-weight: 400;
  cursor:pointer;
}

.li-selector:hover{
  background-color: rgba(217, 237, 247, 1);
}

.li-selected{
  background-color: rgba(231, 244, 253, 1);
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// 2.8.1 | 2022-11-21 | mmcc | STRY0132316 - Tasker User Profile Page- Add Component Selector - User Settings Container Widget
//                                      New widget created 
//                                      Changes made in HTML, CSS, Server script and Client controller.
// 2.8.1 | 2022-11-24 | raj | STRY0132318 - Tasker User Profile- New Component- "Out of Office Schedule" - Profile Card View
//                                      Changes made in HTML, added flex-column flex-grow to both of the sidebar selector divs
//                                      The out of office widget was not stretching to fill the page
// 2.8.1 | 2022-09-21| raj  |  STRY0130635 - Task Form- Assignee is Out of Office
//																			Changes made in Server Script to pass in the tab to load.  This is used by the OOO tooltip
//                                      Changes made in cliet script to allow sidebarMenuItem to be set by the server
//                                      
// 2.8.1 | 2023-01-03 | mmcc | STRY0130942 - Tasker User Profile as Modal
//                                      In HTML, added a footer div for the OK button to close the modal
//                                      In Server script, load message for the OK button into submitButtonText
//                                      In Client controller, added onSubmit()
//                                      Changes made in HTML, Server script and Client controller.
// 2.8.5 | 2023-06-16 | mmcc | DFCT0011586 - Existing Task form >"Show me all the Out of Office Schedules...">Tasker User Settings Container 
//                                       modal>"User Profile" should NOT overlap on the Profile component
//                                      In HTML, updated <div> to use an ngclass based on isModal to use .dtech-flex-grow-0dot2-shrink-1-basis-0p
//                                       or .dtech-flex-grow-0dot25-shrink-1-basis-0p to stop left side menu text from wrapping in a modal 
//                                      Changes made in HTML.
//
//------------------------------------------------------------------------------------------------------------------------
(function(input, data, options) {

	main();

	function main() {
		// get ready to load messages for this widget
		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('tasker_user_settings_container');
		// load messages
		data.messages = [];
		data.messages = taskWidgetIconsAndMessage.loadMessages();

		// 2.8.1 | 2023-01-03 | mmcc | STRY0130942 - Tasker User Profile as Modal
		data.submitButtonText = data.messages['Tasker - Button - OK'];
		data.submitButtonTitle = ''; // data.messages['Tasker - Button - OK'];

		data.sidebarMenuList = [];
		// Build sidebar menu list
		data.sidebarMenuList.push(data.messages['Tasker - User Profile']);
		data.sidebarMenuList.push(data.messages['Tasker - Out of Office Schedule']);

		// Directive dtechPopoverList uses widgetInput, so use input
		// DTechApps Tasker Stock Header sends a user id in the URL, so use getParameter()
		// as last resort get the logged in User's ID, so use getUserID()
		data.sysUserID = (input || {}).sys_id || (options || {}).sys_id || $sp.getParameter('sys_id') || gs.getUserID();

		data.bifold = (input || {}).bifold || (options || {}).bifold || false;
		data.isModal = (input || {}).isModal || (options || {}).isModal || false;
		data.isTopWidget = (input || {}).isTopWidget || (options || {}).isTopWidget || false;

		// STRY0130635
		data.sidebarMenuItem = (input || {}).sidebarMenuItem || (options || {}).sidebarMenuItem || "";

		_convertToBool(['bifold', 'isModal', 'isTopWidget']);
	}

	function _convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}
})(input, data, options);
